SELECT name, reset_value, description
FROM timers
WHERE reset_value = '0x0';

SELECT name, reset_value, rw_access
FROM timers
WHERE timer_id = 0;

SELECT timer_id, name
FROM timers
ORDER BY timer_id;

SELECT COUNT(*) AS log_count
FROM timer_logs
WHERE timer_id = 1;

SELECT document_name
FROM timer_documentation
WHERE timer_id = 0;

SELECT source_name
FROM clock_sources
WHERE timer_id = 0 AND source_value = '0x1';

SELECT average_execution_time 
FROM timer_performance 
WHERE timer_id = 1;

SELECT timer_id, compliance_status
FROM timer_compliance
WHERE compliance_type = 'regulatory compliance';

SELECT COUNT(*) AS running_timers
FROM timer_states
WHERE is_running = 1;

SELECT timer_id, reset_value
FROM timer_resets
WHERE auto_reset = 1;

SELECT DISTINCT timer_id
FROM timer_logs
WHERE change_type = 'configuration';

SELECT is_running
FROM timer_states
WHERE timer_id = 1;
